import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Coins, TrendingUp, Clock } from 'lucide-react';

export default function Dashboard() {
  const [myListings, setMyListings] = useState([]);

  useEffect(() => {
    const saved = JSON.parse(localStorage.getItem('myListings')) || [];
    setMyListings(saved);
  }, []);

  return (
    <div className="p-10 space-y-10">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-teal-600 p-8 rounded-[40px] text-white shadow-xl shadow-teal-600/20">
          <Coins className="mb-4 opacity-80" />
          <p className="text-xs font-black uppercase tracking-widest opacity-80">Token Balance</p>
          <h2 className="text-4xl font-black mt-1">1,450 <span className="text-sm">WTK</span></h2>
        </div>
      </div>

      <section>
        <h3 className="text-2xl font-black text-slate-900 dark:text-white mb-6">Your Recent Listings</h3>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          {myListings.map(item => (
            <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} key={item.id} className="bg-white dark:bg-slate-900 p-8 rounded-[40px] border border-slate-100 dark:border-slate-800 shadow-sm">
              <span className="text-[10px] font-black text-teal-600 bg-teal-50 dark:bg-teal-900/30 px-3 py-1 rounded-full uppercase tracking-widest">{item.type}</span>
              <h4 className="text-xl font-bold mt-4 dark:text-white">{item.title}</h4>
              <div className="flex justify-between items-center mt-6 pt-6 border-t border-slate-50 dark:border-slate-800">
                <p className="text-slate-400 font-bold text-sm">{item.location}</p>
                <p className="text-teal-600 font-black">{item.wtk} WTK</p>
              </div>
            </motion.div>
          ))}
          {myListings.length === 0 && <p className="text-slate-400 font-medium">No listings published yet.</p>}
        </div>
      </section>
    </div>
  );
}
